import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm employs a cooperative strategy where each truck communicates its intended next node, and the algorithm adjusts choices to minimize overlapping routes and ensure effective coverage by considering potential blockage scenarios, thus prioritizing nodes that might be left isolated due to the current decisions of other trucks.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    isolation_scores = {}

    for node in unvisited_nodes:
        potential_blockage = sum(1 for truck in truck_nodes if truck != node and distance_matrix[truck, node] < distance_matrix[current_node, node])
        isolation_scores[node] = distance_matrix[current_node, node] + potential_blockage

    next_node = min(isolation_scores, key=isolation_scores.get)

    return next_node
